1	/**
2	 * Bot-to-Bot Relay — dual transport: Upstash Redis + Telegram bot-to-bot.
3	 *
4	 * Architecture:
5	 *   sendRelay(msg) -> transport switch:
6	 *     "redis"    -> LPUSH to Redis list "relay:<targetBot>"
7	 *     "telegram" -> bot.api.sendMessage(@targetBotUsername, text)
8	 *     "both"     -> telegram first, redis as fallback
9	 *   + sendMessage to group (mirror)
10	 *
11	 *   Incoming:
12	 *     Redis poller -> RPOP from "relay:<myName>" -> inject handler
13	 *     Bot handler  -> from.is_bot + allowedBotIds -> inject handler
14	 *
15	 * Redis-only incoming relay messages are mirrored by commands/relay.ts after
16	 * transport de-duplication. Telegram relay uses sender-side group mirrors so
17	 * each conversational message appears once in the shared group.
18	 */
19	import { stat } from "node:fs/promises";
20	import path from "node:path";
21	import { InputFile, type Bot } from "grammy";
22	import { config } from "./config.js";
23	
24	export type RelayTransport = "redis" | "telegram" | "both";
25	
26	export interface RelayConfig {
27	  redisUrl: string;
28	  redisToken: string;
29	  groupChatId: number;
30	  botName: string;
31	  transport: RelayTransport;
32	  targetBotUsername: string; // e.g. "@RK_AI_Codex_bot" for telegram transport
33	  maxConsecutiveTurns: number;
34	}
35	
36	interface RelayMessage {
37	  from: string;
38	  text: string;
39	  ts: string;
40	}
41	
42	let cfg: RelayConfig | null = null;
43	let bot: Bot | null = null;
44	let pollTimer: ReturnType<typeof setInterval> | null = null;
45	let heartbeatTimer: ReturnType<typeof setInterval> | null = null;
46	let onIncoming: ((msg: RelayMessage) => void) | null = null;
47	let idleCount = 0;
48	const IDLE_MAX = 40; // ~2 min at 3s interval -> auto-stop
49	const HEARTBEAT_MS = 30_000; // low-freq check for unsolicited incoming
50	const IMG_EXT = new Set([".jpg", ".jpeg", ".png", ".gif", ".webp", ".bmp"]);
51	const PHOTO_MAX_BYTES = 10 * 1024 * 1024;
52	
53	export interface RelayRuntimeStatus {
54	  configured: boolean;
55	  botName: string | null;
56	  transport: RelayTransport | null;
57	  transportLabel: string;
58	  groupChatId: number | null;
59	  targetBotUsername: string | null;
60	  redisConfigured: boolean;
61	  telegramConfigured: boolean;
62	  redisPollerExpected: boolean;
63	  redisPollerActive: boolean;
64	  heartbeatActive: boolean;
65	  maxConsecutiveTurns: number | null;
66	}
67	
68	export function describeRelayTransport(transport: RelayTransport | null): string {
69	  if (transport === "redis") return "redis only";
70	  if (transport === "telegram") return "telegram only";
71	  if (transport === "both") return "telegram primary + redis fallback";
72	  return "not configured";
73	}
74	
75	export function getRelayRuntimeStatus(): RelayRuntimeStatus {
76	  if (!cfg) {
77	    return {
78	      configured: false,
79	      botName: null,
80	      transport: null,
81	      transportLabel: describeRelayTransport(null),
82	      groupChatId: null,
83	      targetBotUsername: null,
84	      redisConfigured: false,
85	      telegramConfigured: false,
86	      redisPollerExpected: false,
87	      redisPollerActive: false,
88	      heartbeatActive: false,
89	      maxConsecutiveTurns: null,
90	    };
91	  }
92	  const redisConfigured = !!(cfg.redisUrl && cfg.redisToken);
93	  const telegramConfigured = !!cfg.targetBotUsername;
94	  return {
95	    configured: true,
96	    botName: cfg.botName,
97	    transport: cfg.transport,
98	    transportLabel: describeRelayTransport(cfg.transport),
99	    groupChatId: cfg.groupChatId,
100	    targetBotUsername: cfg.targetBotUsername || null,
101	    redisConfigured,
102	    telegramConfigured,
103	    redisPollerExpected: cfg.transport !== "telegram" && redisConfigured,
104	    redisPollerActive: !!pollTimer,
105	    heartbeatActive: !!heartbeatTimer,
106	    maxConsecutiveTurns: cfg.maxConsecutiveTurns,
107	  };
108	}
109	
110	function redisKey(target: string): string {
111	  return `relay:${target}`;
112	}
113	
114	function isUnderAllowedRoot(abs: string): boolean {
115	  const roots = [config.sessionCwd, ...config.sendFileRoots];
116	  const normAbs = path.resolve(abs).toLowerCase();
117	  return roots.some((root) => {
118	    const r = path.resolve(root).toLowerCase().replace(/[\\/]+$/, "");
119	    if (normAbs === r) return true;
120	    return normAbs.startsWith(r + "\\") || normAbs.startsWith(r + "/");
121	  });
122	}
123	
124	async function redisCommand(command: string[]): Promise<{ result: unknown }> {
125	  if (!cfg) throw new Error("Relay not initialized");
126	  const res = await fetch(cfg.redisUrl, {
127	    method: "POST",
128	    headers: {
129	      Authorization: `Bearer ${cfg.redisToken}`,
130	      "Content-Type": "application/json",
131	    },
132	    body: JSON.stringify(command),
133	  });
134	  if (!res.ok) {
135	    const body = await res.text();
136	    throw new Error(`Redis ${command[0]} failed: ${res.status} ${body}`);
137	  }
138	  return res.json() as Promise<{ result: unknown }>;
139	}
