141	/** Start polling if not already running. */
142	export function ensurePollerRunning(): void {
143	  if (pollTimer || !cfg) return;
144	  idleCount = 0;
145	  pollTimer = setInterval(poll, 3000);
146	  console.log(`[relay] poller activated`);
147	}
