268	/** Poll Redis for incoming messages. */
269	async function poll(): Promise<void> {
270	  if (!cfg || !bot) return;
271	  const key = redisKey(cfg.botName);
272	  try {
273	    const { result } = await redisCommand(["RPOP", key]);
274	    if (result === null || typeof result !== "string") {
275	      idleCount++;
276	      if (idleCount >= IDLE_MAX && pollTimer) {
277	        clearInterval(pollTimer);
278	        pollTimer = null;
279	        console.log(`[relay] high-freq poller stopped after ${IDLE_MAX} idle cycles`);
280	      }
281	      return;
282	    }
283	    idleCount = 0;
284	    ensurePollerRunning();
285	    const msg: RelayMessage = JSON.parse(result);
286	    // Dedup: skip if already received via telegram bot-to-bot
287	    if (isDuplicate(msg.from, msg.text)) {
288	      console.log(`[relay] dedup: skipping redis message from "${msg.from}"`);
289	      return;
290	    }
291	    console.log(`[relay] ✓ received via REDIS from "${msg.from}"`);
292	    if (onIncoming) onIncoming(msg);
293	  } catch (err) {
294	    console.error("[relay] poll error:", err);
295	  }
296	}
