334	/** Quick connectivity test - SET + GET + DEL a test key. */
335	export async function testRedisConnection(relayConfig: RelayConfig): Promise<boolean> {
336	  cfg = relayConfig;
337	  try {
338	    await redisCommand(["SET", "relay:_ping", "pong", "EX", "10"]);
339	    const { result } = await redisCommand(["GET", "relay:_ping"]);
340	    await redisCommand(["DEL", "relay:_ping"]);
341	    return result === "pong";
342	  } catch (err) {
343	    console.error("[relay] connection test failed:", err);
344	    return false;
345	  } finally {
346	    cfg = relayConfig;
347	  }
348	}
