350	// ─── Dedup for "both" mode ─────────────────────────────────────────────────
351	const recentHashes = new Set<string>();
352	const DEDUP_TTL_MS = 10_000;
353	
354	function dedupKey(from: string, text: string): string {
355	  // Simple hash: first 100 chars of text + sender
356	  return `${from}:${text.slice(0, 100)}`;
357	}
358	
359	/** Returns true if this message is a duplicate (already seen recently). */
360	export function isDuplicate(from: string, text: string): boolean {
361	  const key = dedupKey(from, text);
362	  if (recentHashes.has(key)) return true;
363	  recentHashes.add(key);
364	  setTimeout(() => recentHashes.delete(key), DEDUP_TTL_MS);
365	  return false;
366	}
367	
368	// ─── Telegram bot-to-bot incoming handler ──────────────────────────────────
369	const RELAY_PREFIX_RE = /^\[RELAY:([^\]]+)\]\s*/;
370	
371	export interface ParsedBotRelay {
372	  from: string;
373	  text: string;
374	}
375	
376	/** Parse an incoming bot message. Returns null if not a relay message. */
377	export function parseBotRelayMessage(rawText: string): ParsedBotRelay | null {
378	  const m = RELAY_PREFIX_RE.exec(rawText);
379	  if (!m) return null;
380	  return { from: m[1], text: rawText.slice(m[0].length) };
381	}
382	
383	/** Get the registered incoming handler (set by startRelayPoller). */
384	export function getRelayHandler(): ((msg: RelayMessage) => void) | null {
385	  return onIncoming;
386	}
